import{_ as t,o as r,c as a,a5 as o}from"./chunks/framework.BWEfNu6d.js";const u=JSON.parse('{"title":"kcp","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/kcp.md","filePath":"reference/components/kcp.md"}'),c={name:"reference/components/kcp.md"};function i(n,e,s,d,p,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="kcp" tabindex="-1">kcp <a class="header-anchor" href="#kcp" aria-label="Permalink to &quot;kcp&quot;">​</a></h1><p><a href="https://docs.kcp.io/kcp/main/" target="_blank" rel="noreferrer">kcp</a> is a Kubernetes-style API server with the container orchestration removed. It keeps the declarative API control plane — workspaces, CRDs, RBAC, the watch/list/reconcile model — and turns it into a substrate for managing arbitrary services through KRM.</p><p>Platform Mesh runs on top of kcp. Every Platform Mesh account, organization, provider, and marketplace surface is a kcp workspace; every cross-account interaction goes through <code>APIExport</code> / <code>APIBinding</code>; every authentication and authorization decision passes through kcp&#39;s chain.</p><h2 id="why-kcp" tabindex="-1">Why kcp <a class="header-anchor" href="#why-kcp" aria-label="Permalink to &quot;Why kcp&quot;">​</a></h2><ul><li><strong>One API per account.</strong> Each kcp workspace is an isolated Kubernetes-shaped API endpoint with its own resources, RBAC, and identity. Platform Mesh maps the <a href="/pr-preview/pr-131/concepts/account-model.html">account model</a> directly onto the workspace tree.</li><li><strong>Cheap multi-tenancy.</strong> Workspaces share a single process and etcd, isolated by storage prefix. No per-tenant cluster.</li><li><strong>Cross-workspace API sharing.</strong> Service providers publish APIs once via <code>APIExport</code>; consumers bind them into their workspace and use them like native resources. See <a href="./kcp/api-sharing.html">API sharing</a>.</li><li><strong>Pluggable identity and authorization.</strong> OIDC plugs into the front proxy, OpenFGA plugs into the authorizer chain via the <a href="./rebac-authz-webhook.html">rebac-authz-webhook</a>. See <a href="./kcp/identity-and-authorization.html">Identity and authorization</a>.</li><li><strong>Workspace-aware controllers.</strong> <a href="./api-syncagent.html">api-syncagent</a>, <a href="./account-operator.html">account-operator</a>, and <a href="./security-operator.html">security-operator</a> reconcile across workspaces using kcp&#39;s virtual-workspace endpoints. See <a href="./kcp/watch-and-sync.html">Watch and sync</a> and <a href="./kcp/virtual-workspaces.html">Virtual workspaces</a>.</li></ul><h2 id="what-platform-mesh-uses-from-kcp" tabindex="-1">What Platform Mesh uses from kcp <a class="header-anchor" href="#what-platform-mesh-uses-from-kcp" aria-label="Permalink to &quot;What Platform Mesh uses from kcp&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>What it covers</th></tr></thead><tbody><tr><td><a href="./kcp/workspaces.html">Workspaces</a></td><td><code>Workspace</code>, <code>WorkspaceType</code>, <code>LogicalCluster</code>, hierarchical paths, the <code>orgs</code> and <code>account</code> types Platform Mesh defines.</td></tr><tr><td><a href="./kcp/api-sharing.html">API sharing</a></td><td><code>APIExport</code>, <code>APIBinding</code>, <code>APIResourceSchema</code>, permission claims, identity hash, <code>APIExportEndpointSlice</code>.</td></tr><tr><td><a href="./kcp/identity-and-authorization.html">Identity and authorization</a></td><td>Front proxy, OIDC (<code>AuthenticationConfiguration</code> + <code>WorkspaceAuthenticationConfiguration</code>), <code>AuthorizationConfiguration</code> chain, rebac-authz-webhook wiring.</td></tr><tr><td><a href="./kcp/virtual-workspaces.html">Virtual workspaces</a></td><td><code>/services/apiexport/...</code> endpoints, reading <code>APIExportEndpointSlice.status</code>, terminating-phase URLs from <code>WorkspaceType.status.virtualWorkspaces</code>.</td></tr><tr><td><a href="./kcp/watch-and-sync.html">Watch and sync</a></td><td><code>multicluster-provider</code>, <code>pathaware</code> and <code>apiexport</code> flavors, <code>mcreconcile.Request</code>, <code>manager.GetCluster()</code>.</td></tr><tr><td><a href="./sharding.html">Sharding</a></td><td>Sharded topology in Platform Mesh local setup and production.</td></tr></tbody></table><p><a href="./kcp-operator.html">kcp-operator</a> deploys kcp itself: <code>RootShard</code>, <code>Shard</code>, <code>FrontProxy</code>, <code>CacheServer</code>, and <code>Kubeconfig</code> CRs. It is a sibling component, not part of kcp.</p><h2 id="kcp-io-annotations-platform-mesh-reads-or-writes" tabindex="-1">kcp.io annotations Platform Mesh reads or writes <a class="header-anchor" href="#kcp-io-annotations-platform-mesh-reads-or-writes" aria-label="Permalink to &quot;kcp.io annotations Platform Mesh reads or writes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Annotation</th><th>Set by</th><th>Used by</th></tr></thead><tbody><tr><td><code>kcp.io/cluster</code></td><td>kcp on objects returned through wildcard / virtual-workspace reads</td><td>Platform Mesh controllers to identify the source workspace</td></tr><tr><td><code>kcp.io/path</code></td><td>kcp on <code>LogicalCluster</code></td><td>Platform Mesh controllers for routing and <code>Workspace.spec.type.path</code> references</td></tr><tr><td><code>authorization.kcp.io/required-groups</code></td><td>platform owners, on workspaces</td><td>kcp authorizer chain (required-groups stage)</td></tr><tr><td><code>authentication.kcp.io/scopes</code></td><td>tooling</td><td>kcp front proxy / authentication</td></tr></tbody></table><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li>Upstream: <a href="https://github.com/kcp-dev/kcp" target="_blank" rel="noreferrer">kcp-dev/kcp</a></li><li>Operator: <a href="https://github.com/kcp-dev/kcp-operator" target="_blank" rel="noreferrer">kcp-dev/kcp-operator</a> — see <a href="./kcp-operator.html">kcp-operator</a></li><li>Multi-cluster client: <a href="https://github.com/kcp-dev/multicluster-provider" target="_blank" rel="noreferrer">kcp-dev/multicluster-provider</a></li><li>Upstream docs: <a href="https://docs.kcp.io/kcp/main/" target="_blank" rel="noreferrer">docs.kcp.io</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-131/concepts/control-planes.html">Control planes and workspaces</a></li><li><a href="/pr-preview/pr-131/concepts/api-sharing.html">API sharing</a></li><li><a href="/pr-preview/pr-131/concepts/identity-and-authorization.html">Identity and authorization</a></li><li><a href="/pr-preview/pr-131/concepts/architecture.html">Architecture</a></li></ul>',14)])])}const k=t(c,[["render",i]]);export{u as __pageData,k as default};
